class Solution {
public:
    int shortestMatchingSubstring(string s, string p) {
        int m = p.size();
        int n = s.size();
        int res = n + 1;
        for (int i = 0; i <= n - m; i++) {
            int j = 0, k = 0;
            while (j < m) {
                if (p[j] == '*') {
                    while (k < m && p[k] == '*') k++;
                    j = k;
                } else if (s[i + j] == p[j]) {
                    j++;
                } else {
                    break;
                }
            }
            if (j == m) res = min(res, i + m);
        }
        return res > n ? -1 : res;
    }
};
